INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00026', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「我在普林斯頓大學的同事，寫了一篇論文反駁一個在大學生中流行的迷 思。他在〈不顧需求為顯示博學而濫用華麗詞藻的後果：不必要使用長句 的問題〉的論文中指出，用虛情假意的語言來表達熟悉的想法，是沒有智 慧、可信度低的象徵。」 上文所指「一個在大學生中流行的迷思」應是：', '["引經據典能讓自己的觀點更具說服力", "用繁複語言表述平常概念以顯得高明", "簡短的文句才能使言不由衷不被察覺", "博學的身分比較能提高文章的可信度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00027', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「最近研究發現，壓力太大導致的肥胖，脂肪容易積存在腹部，這是造成『三 高』和『代謝症候群』的元凶。壓力已是現代人的宿命，最重要的是找出壓 力的來源，尋求改善；假使無法改善，心念轉移、暫時離開壓力現場、深呼 吸、做做伸展操都是很好的方式，正常作息和規律運動是降低壓力的不二法 門，壓力大到無法承受時，可以尋求心理治療師或是醫師的協助。」 根據上文，下列選項正確的是：', '["「三高」和「代謝症候群」的病患，都是肥胖者", "減少壓力來源，是避免罹患「三高」的有效方法", "若能找出壓力的來源，就能有效改善肥胖的病症", "一旦感到工作有壓力時，應立即尋求醫師的協助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00028', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「人與人相處，你不能蠻橫的要求對方的心情必須永遠是春天。朋友難免 有心情壞的時候，難免失言、失態、失禮、失約。那時候，只有像豆腐那 樣柔軟的寬厚心情，才能夠容忍對方一時的過失。朋友相交，如果沒有『豆 腐修養』，很可能造成終身的遺憾。最令我難忘的朋友，並不是那曾經對 待我很熱情的，而是那曾經寬恕我的過失的。」 根據上文，最讓作者難忘的朋友具有什麼樣的特質？', '["有容乃大，像豆腐的柔軟", "纖塵不染，像豆腐的潔白", "沁人心脾，像豆腐的營養", "澹泊自甘，像豆腐的美味"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00029', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「三月的瑪德琳娜島，是二十五萬隻豎琴海豹群聚哺育幼豹的時刻。離群 的小海豹聽見母海豹的呼聲，努力朝母海豹這邊爬。大海豹和小海豹在最 接近的時刻，牠們用鼻尖碰觸廝磨，確認是自家的孩子後，母海豹就開始 哺乳。在茫茫的雪地上，與小海豹四目相望那一刻，真叫人怦然心動。生 命中總有一種突然，教你驚覺某個靈魂正與你凝視，有一種交會可以消弭 萬物的界線。遍地寒冰中，失散的雌海豹和幼海豹，能藉著鼻尖的碰觸確 認彼此；芸芸眾生中，總也有那樣特別的人兒，能熟悉你的頻率認出你的 氣味。老天給候鳥以季節，給人類以親子，那種無形的召喚，讓人嗅得到 回家的航線。」 根據上文，下列選項何者最符合文意？', '["以海豹的親子關係，呼應人類的天倫之情", "以動物親子間親密互動，暗喻人類親子關係不如動物", "哺乳類動物的表現雖與人類雷同，但文中的描寫是想像而非真實", "有一種交會可以消弭萬物界線，但無法期待人們能熟悉彼此頻率認出氣味"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00030', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「通常，我們受了傷之後，總會慣性的想要壓抑，然後就當成這件事情過 了，很少再有機會回頭檢視這些傷痕。畢竟我們總是會想，算了，事情過 去就過去了，再回頭看有什麼意義呢？為什麼要再勾起那些傷痛呢？但 是，如果傷痛都過去了，回頭去看，又何妨？當你真的願意鼓起勇氣，進 入不敢面對的傷痛，反而會讓你擁有一份安詳。」 根據上文，下列選項最符合文意的是：', '["面對傷痛有助於繼續平靜生活", "掀開以前的傷痕可以告別過往", "原諒傷害者的同時也放過自己", "習慣性壓抑可避免再度受傷害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00031', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「牛肉麵吃多了，稍微失察，不免覺得大同小異，有時踟躕街頭，忽然升 起一種孤獨感，喟歎覓一碗可口的牛肉麵竟如此難得，心灰意冷，頗有獨 孤求敗的蒼涼感。坊間新近出版一本《牛肉麵評鑑》，我買了一本，按圖 索麵，到處尋找還沒吃過的店，試驗了幾家，決定不如繼續流浪街頭，自 己一家一家地碰運氣。」 根據上文，下列選項何者正確？', '["文中所謂的「獨孤求敗」，是因為作者想找出坊間失敗的牛肉麵店家", "作者決定繼續「流浪街頭」，是為了籌措品嚐美食的基金，必須省吃儉用", "對於坊間出版的《牛肉麵評鑑》一書，作者所持的態度是「盡信書不如 無書」", "作者之所以興起蒼涼感，是因為常年在巷弄間尋訪，嚐遍各種牛肉麵後， 覺得運氣不佳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00032', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '下列詞句中，何者沒有語病？', '["今天天氣十分非常炎熱，令人感到沉悶愛睏", "人生必須逐夢踏實，為自己的未來不斷努力", "他已經走投無路，不得不鋌而走險冒險去犯罪", "為了因應對付未知的疾病，人們戴口罩不鬆懈"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00033', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「我年輕的時候不會想，不知道這些料理有可能是母親獨有的創意或發 明，或者這些東西有來歷，卻又被母親詮釋成自己的風格；我總以為它們 是很普遍也普通的存在，也許每個人家的母親都會煮。等失去母親之後， 我才知道『百母百味』，每位母親其實都是不同的，就算是一道共通的菜 色，每位母親做起來，味道也是完全不同的。」 根據上文，下列選項敘述最適當的是：', '["年輕時，作者以為母親的料理，家家戶戶的母親都會做", "中年後，作者發現母親做菜樸實無華，不如想像中厲害", "失去母親後，作者憑記憶嘗試復刻母親料理的百種滋味", "自己做菜後，作者將母親的私房料理詮釋成自己的風格"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00034', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「關於個人道德觀念的取得，近年來的研究認為，來自文化社群其他成員 的教誨固然極為重要，但道德準則的吸收能力卻顯然是因人而異。這種接 納道德標準和實踐道德行為的能力，就是遺傳的重要貢獻。」 根據上文，下列選項何者最符合文意？', '["道德行為來自於個人的思考與推理的結果", "個人道德觀念的塑造，主要來自社會環境", "個人道德觀念的取得，受天性與學習影響", "遺傳是影響個人道德觀念形成的全部因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00035', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '「每次讚揚讀書，總沒有機會說清楚讀前和讀後境界的不同：讀前三部曲 是先定領域，再去翻書，最後才選定待讀的書。（我最喜歡先讀書序和目 錄）翻書初期氣壯山河，翻久了好似吞象的老鼠，恨自己生命的限制；真 正讀過的書引人沉思，幫我在現實生活中進可攻，退可守。」 根據上文，有關作者讀書的方法與感受，下列敘述最適當的是：', '["通常先讀書序和目錄再決定待讀之書的領域", "翻書初期氣壯山河是指一開始閱讀速度飛快", "以吞象的老鼠來形容自己經常無法將書讀完", "認為真正讀過的書能夠啟迪人心並拿來運用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
